import{c as l,Q as r,j as t,m as i}from"./chunks/framework.4b-lwRvT.js";const d=JSON.parse('{"title":"库工程规划","description":"","frontmatter":{"title":"库工程规划"},"headers":[],"relativePath":"planning/libraries.md","filePath":"planning/libraries.md","lastUpdated":1779684191000}'),n={name:"planning/libraries.md"};function e(s,o,a,g,u,c){return r(),t("div",null,[...o[0]||(o[0]=[i('<blockquote><p>PS：库工程是我们后面快速开展做快速迭代产品的重要基石，所以，将我们的产品预备役一些库，和从过去的产品中制作一些库是非常重要的。</p></blockquote><h2 id="单片机层次" tabindex="-1">单片机层次 <a class="header-anchor" href="#单片机层次" aria-label="Permalink to &quot;单片机层次&quot;">​</a></h2><h3 id="常见驱动" tabindex="-1">常见驱动 <a class="header-anchor" href="#常见驱动" aria-label="Permalink to &quot;常见驱动&quot;">​</a></h3><blockquote><p>常见驱动包括基于C和C++版本的高性能驱动，涵盖GPIO, UART, SPI/IIC等</p></blockquote><p><strong>目标</strong>：基于 C/C++ 的高性能封装，<strong>强制要求 DMA 和 中断 (IRQ) 支持</strong>，不能仅仅是轮询。</p><ul><li><strong>基础通信类</strong>： <ul><li><strong>GPIO</strong>: 输入/输出，中断模式（上升/下降/双边），去抖动逻辑（软件/硬件）。</li><li><strong>UART/USART</strong>: 支持 RingBuffer 的中断接收/发送，<strong>DMA 接收/发送</strong>（解决高速数据丢包），波特率自适应。</li><li><strong>SPI</strong>: 主/从模式，DMA 传输，支持多片选管理 (Software CS)。</li><li><strong>I2C (IIC)</strong>: 硬件 I2C (DMA 支持) + <strong>高健壮性模拟 I2C</strong>（防止死锁，带超时复位机制）。</li><li><strong>CAN/CAN-FD</strong>: 过滤器配置，FIFO 管理，针对汽车/工业场景的协议解析基础。</li><li><strong>USB Device/Host</strong>: 虚拟串口 (CDC), 模拟U盘 (MSC), HID (键盘鼠标)。</li></ul></li><li><strong>定时与控制类</strong>： <ul><li><strong>TIM (Timer)</strong>: 基础定时，PWM 输出 (互补波形/死区控制 - 电机用)，输入捕获 (编码器模式)。</li><li><strong>RTC</strong>: 实时时钟，支持闹钟中断，Unix 时间戳转换。</li><li><strong>WDT</strong>: 看门狗 (独立/窗口)，提供“喂狗”回调接口。</li></ul></li><li><strong>模拟与转换类</strong>： <ul><li><strong>ADC</strong>: 多通道扫描，DMA 自动搬运，内部温度/电压参考计算。</li><li><strong>DAC</strong>: 波形输出，音频播放基础。</li></ul></li><li><strong>系统级</strong>： <ul><li><strong>Flash (Internal)</strong>: 片内 Flash 读写（带扇区擦除保护）。</li><li><strong>CRC/RNG</strong>: 硬件 CRC 校验，真随机数生成。</li></ul></li></ul><h3 id="常见器件驱动" tabindex="-1">常见器件驱动 <a class="header-anchor" href="#常见器件驱动" aria-label="Permalink to &quot;常见器件驱动&quot;">​</a></h3><blockquote><p>编写常见器件的驱动：包含但是不限于SSD13*系列芯片，LCD，常见ROM存储器，SD卡等驱动</p></blockquote><p><strong>目标</strong>：模块化设计，也就是“驱动对象化”，支持同一类设备挂载多个。</p><ul><li><strong>人机交互 (HMI)</strong>： <ul><li><strong>显示屏</strong>: <ul><li>OLED: SSD1306, SSD1315, SH1106 (I2C/SPI).</li><li>TFT LCD: ST7789, ILI9341, ST7735, LTDC (RGB接口屏).</li><li>墨水屏: e-Paper 驱动 (局部刷新/全局刷新).</li></ul></li><li><strong>输入设备</strong>: <ul><li>按键: 矩阵按键，长按/短按/双击事件封装。</li><li>旋钮编码器 (EC11)。</li><li>触摸: 电容触摸 (GT911, FT6236), 电阻触摸 (XPT2046).</li></ul></li><li><strong>指示</strong>: WS2812/SK6812 (RGB LED)，状态机控制的 LED 闪烁库。</li></ul></li><li><strong>存储器 (Storage)</strong>： <ul><li><strong>EEPROM</strong>: AT24Cxx 系列。</li><li><strong>NOR Flash</strong>: W25Qxx 系列 (SPI/QSPI)。</li><li><strong>NAND Flash</strong>: 坏块管理，磨损均衡 (FTL层基础)。</li><li><strong>SD Card</strong>: SDIO 模式 (高速) 与 SPI 模式兼容。</li></ul></li><li><strong>传感器 (Sensors) - 工业与消费级</strong>： <ul><li><strong>IMU (姿态)</strong>: MPU6050, LSM6DS3, ICM20602 (带简单的姿态解算滤波算法如互补滤波/卡尔曼)。</li><li><strong>环境</strong>: 温湿度 (DHT11/22, AHT10, SHT30), 气压 (BMP280, SPL06).</li><li><strong>光/距</strong>: 光照 (BH1750), 距离 (VL53L0X ToF, 超声波 HC-SR04).</li></ul></li><li><strong>连接模组 (Connectivity)</strong>： <ul><li><strong>WiFi/BT</strong>: ESP8266/ESP32 AT 指令集封装，Air724 (4G Cat.1).</li><li><strong>IoT</strong>: LoRa (SX1278/SX1262), NBIoT (BC26).</li></ul></li></ul><h3 id="其他重要的middlewares" tabindex="-1">其他重要的Middlewares <a class="header-anchor" href="#其他重要的middlewares" aria-label="Permalink to &quot;其他重要的Middlewares&quot;">​</a></h3><blockquote><p>这一部分迁移和完善之前的<a href="https://github.com/CCUtilCommons/CCBasicCore" target="_blank" rel="noreferrer">CCUtilCommons/CCBasicCore: CCBasicCore is the center library of CCUtilsCommons, which attempts to provide simple DataStructure And Simple Algorithm for Any Platform</a></p></blockquote><ul><li><strong>数据结构</strong>: 线程安全的 RingBuffer, LinkedList, Queue.</li><li><strong>格式解析</strong>: cJSON (精简版), XML (Mini), IniParser.</li><li><strong>调试</strong>: 基于宏定义的日志系统 (Log_Debug/Info/Error)，支持重定向到串口/RTT/USB。</li><li><strong>OS抽象层 (OSAL)</strong>: 封装 Task, Mutex, Semaphore, Queue，统一 FreeRTOS, RT-Thread 和裸机的接口。</li></ul><h3 id="上层框架" tabindex="-1">上层框架 <a class="header-anchor" href="#上层框架" aria-label="Permalink to &quot;上层框架&quot;">​</a></h3><h4 id="显示库驱动" tabindex="-1">显示库驱动 <a class="header-anchor" href="#显示库驱动" aria-label="Permalink to &quot;显示库驱动&quot;">​</a></h4><blockquote><p>做一个炫酷的嵌入式UI框架，可以轻量级的开箱即用</p></blockquote><p><strong>目标</strong>：在资源受限（如 STM32F1/F4）芯片上实现高帧率动画，或在高性能芯片上实现类手机体验。</p><ul><li><strong>渲染引擎 (Render Core)</strong>： <ul><li>实现基本的 2D 绘图原语 (点, 线, 圆, 矩形, 填充)。</li><li><strong>DMA2D/GPU 加速接口</strong>: 如果芯片支持，自动使用硬件加速。</li><li><strong>双缓冲 (Double Buffering)</strong>: 防止画面撕裂。</li></ul></li><li><strong>控件系统 (Widget System)</strong>： <ul><li><strong>基础控件</strong>: Label (支持多字体), Button (带按下动效), Switch, Slider, ProgressBar.</li><li><strong>高级控件</strong>: List/Wheel (滚轮选择), Chart (波形图), Image (支持 PNG 解码/RLE 压缩).</li></ul></li><li><strong>动画引擎 (Animation Engine)</strong>： <ul><li>提供 <strong>缓动函数 (Easing Functions)</strong>: 实现弹跳、渐入渐出、惯性滑动等效果。</li><li><strong>页面管理器 (Page Manager)</strong>: 页面栈管理，负责页面切换时的转场动画（推入、覆盖、淡入）。</li></ul></li><li><strong>工具链</strong>: <ul><li>PC 端模拟器 (基于 SDL2 或 Windows API)，允许在电脑上开发 UI。</li><li>字体/图片转换工具 (脚本化)。</li></ul></li></ul><h2 id="嵌入式linux层级" tabindex="-1">嵌入式Linux层级 <a class="header-anchor" href="#嵌入式linux层级" aria-label="Permalink to &quot;嵌入式Linux层级&quot;">​</a></h2><h3 id="系统编程库" tabindex="-1">系统编程库 <a class="header-anchor" href="#系统编程库" aria-label="Permalink to &quot;系统编程库&quot;">​</a></h3><blockquote><p>目的：这一部分是熟悉和讲解系统编程的几个非常重要的概念，以及为了之后快速的起一些嵌入式Or上位机联动调试的时候方便检查时做的</p></blockquote><h4 id="_3-1-系统编程库-system-programming-lib" tabindex="-1">3.1 系统编程库 (System Programming Lib) <a class="header-anchor" href="#_3-1-系统编程库-system-programming-lib" aria-label="Permalink to &quot;3.1 系统编程库 (System Programming Lib)&quot;">​</a></h4><p><strong>目标</strong>：封装 POSIX 标准 API，提供现代 C++ (C++11/14/17) 风格的接口，方便上位机联动调试。</p><ul><li><strong>硬件访问封装 (HW Access)</strong>： <ul><li><strong>GPIO</strong>: 封装 <code>sysfs</code> 或新版 <code>libgpiod</code>，实现类似单片机的操作风格。</li><li><strong>Serial</strong>: 封装 <code>termios</code>，处理粘包/分包，提供阻塞/非阻塞读写。</li><li><strong>I2C/SPI Userspace</strong>: 封装 <code>/dev/i2c-x</code> 和 <code>spidev</code>，方便在应用层驱动外设。</li></ul></li><li><strong>进程间通信 (IPC)</strong>： <ul><li><strong>Shared Memory</strong>: 高速数据共享封装。</li><li><strong>Unix Domain Socket</strong>: 本地进程高效通信，用于 Daemon 和 UI 交互。</li><li><strong>Message Queue</strong>: 封装 POSIX MQ 或 System V MQ。</li></ul></li><li><strong>并发与线程 (Concurrency)</strong>： <ul><li><strong>ThreadPool</strong>: 高性能线程池，避免频繁创建销毁线程。</li><li><strong>Timer</strong>: 基于 <code>timerfd</code> 的高精度定时器封装。</li></ul></li><li><strong>网络通信 (Network)</strong>： <ul><li><strong>TCP/UDP Socket</strong>: 封装 Server/Client 类，处理断线重连、心跳包。</li><li><strong>HTTP Client</strong>: 简单的 REST API 请求封装 (GET/POST/Upload)。</li><li><strong>MQTT Client</strong>: 针对物联网场景的封装。</li></ul></li><li><strong>调试与诊断工具 (Debug Utils)</strong>： <ul><li><strong>Backtrace</strong>: 程序崩溃时自动打印堆栈信息（Segment Fault 捕获）。</li><li><strong>Performance Monitor</strong>: 统计 CPU 占用率、内存使用情况的类。</li><li><strong>Log Daemon</strong>: 统一日志服务，支持日志轮转 (Log Rotation)、存文件、网络上报。</li></ul></li><li>其他常见的 SysAPI</li></ul><h3 id="简单的桌面系统" tabindex="-1">简单的桌面系统 <a class="header-anchor" href="#简单的桌面系统" aria-label="Permalink to &quot;简单的桌面系统&quot;">​</a></h3><blockquote><p>目的：重写一下CCIMXDesktop项目，使其成为完整的迷你嵌入式桌面系统。</p></blockquote><p><strong>目标</strong>：不仅是一个 Demo，而是一个<strong>可扩展的 Mini OS 框架</strong>，适用于工控屏、智能家居中控等场景。</p><h4 id="_4-1-核心架构-core-architecture" tabindex="-1">4.1 核心架构 (Core Architecture) <a class="header-anchor" href="#_4-1-核心架构-core-architecture" aria-label="Permalink to &quot;4.1 核心架构 (Core Architecture)&quot;">​</a></h4><p>采用Qt，迁移之前使用的<a href="https://github.com/Charliechen114514/CCIMXDesktop" target="_blank" rel="noreferrer">Charliechen114514/CCIMXDesktop: This is a Simple Desktop with Common Utilities for Embedded Device System using Qt6</a>，不过这一次是改成挂靠，然后重新开一个分支搞新的</p><h4 id="_4-1-桌面环境组件-desktop-components" tabindex="-1">4.1 桌面环境组件 (Desktop Components) <a class="header-anchor" href="#_4-1-桌面环境组件-desktop-components" aria-label="Permalink to &quot;4.1 桌面环境组件 (Desktop Components)&quot;">​</a></h4><ul><li><strong>System Bar (状态栏)</strong>： <ul><li>显示时间、WiFi 信号、CPU 温度、内存占用。</li><li>下拉菜单（快捷开关：亮度、音量、网络）。</li></ul></li><li><strong>Launcher (应用启动器)</strong>： <ul><li>网格化图标布局，支持滑屏翻页。</li><li>应用生命周期管理（启动 App、杀掉 App、切换前后台）。</li></ul></li><li><strong>Settings (系统设置)</strong>： <ul><li><strong>网络管理</strong>: 扫描 WiFi，输入密码连接 (调用 <code>wpa_supplicant</code> 或 <code>NetworkManager</code> DBus 接口)。</li><li><strong>显示/声音</strong>: 调节背光亮度 (写 <code>/sys/class/backlight</code>)，调节音量 (ALSA API)。</li><li><strong>系统信息</strong>: 版本号、存储空间管理。</li></ul></li></ul><h4 id="_4-3-必备-app-套件" tabindex="-1">4.3 必备 App 套件 <a class="header-anchor" href="#_4-3-必备-app-套件" aria-label="Permalink to &quot;4.3 必备 App 套件&quot;">​</a></h4><ul><li><strong>File Explorer (文件管理器)</strong>: 浏览 U 盘/SD 卡，复制粘贴。</li><li><strong>Terminal (简易终端)</strong>: 在屏幕上直接执行 Shell 命令（虚拟键盘支持）。</li><li><strong>Process Manager (任务管理器)</strong>: 查看并结束占用高的进程。</li></ul><h4 id="_4-4-交互逻辑-interaction" tabindex="-1">4.4 交互逻辑 (Interaction) <a class="header-anchor" href="#_4-4-交互逻辑-interaction" aria-label="Permalink to &quot;4.4 交互逻辑 (Interaction)&quot;">​</a></h4><ul><li><strong>全局手势</strong>: 边缘滑入返回，底部上滑回主页。</li><li><strong>输入法框架</strong>: 简易的虚拟键盘（中英文支持）。</li></ul>',35)])])}const p=l(n,[["render",e]]);export{d as __pageData,p as default};
